const input = $input.first().json;

const patientPhone = input.patient_phone || input.telefone_paciente || null;
const patientName = input.patient_name || input.nome_paciente || null;
const dentistId = input.dentist_id || input.id_dentista || null;
const procedureId = input.procedure_id || input.id_procedimento || null;
const date = input.date || input.data || null;
const time = input.time || input.horario || null;
const notes = input.notes || input.observacoes || ' ';

const errors = [];
if (!patientPhone) errors.push('telefone do paciente');
if (!patientName) errors.push('nome do paciente');
if (!dentistId) errors.push('ID do dentista');
if (!date) errors.push('data da consulta (YYYY-MM-DD)');
if (!time) errors.push('horário (HH:MM)');

if (errors.length > 0) {
  return [{ json: { error: true, message: `Dados obrigatórios faltando: ${errors.join(', ')}. Peça essas informações ao paciente.` } }];
}

return [{ json: { patient_phone: patientPhone, patient_name: patientName, dentist_id: String(parseInt(dentistId)), procedure_id: procedureId ? String(parseInt(procedureId)) : ' ', date, time, notes } }];

const result = $input.first().json;

if (result.error) {
  return [{ json: { resultado: result.mensagem } }];
}

if (result.sucesso) {
  return [{ json: { resultado: `✅ ${result.mensagem} (ID: ${result.id_agendamento}). Enviaremos um lembrete 24h antes. Para cancelar, informe o ID do agendamento.` } }];
} else {
  return [{ json: { resultado: `❌ ${result.mensagem}` } }];
}
